\begin{aligned}
\int \log x d x & =\int \log x \cdot(x)^{\prime} d x=\log x \cdot x-\int(\log x)^{\prime} x d x \\
& =x \log x-\int \frac{1}{x} x d x=x \log x-\int d x \\
& =x \log x-x+C
\end{aligned}

\begin{aligned}
& \int x^\alpha d x=\frac{1}{\alpha+1} x^{\alpha+1}+C \quad(\alpha \neq-1) \\
& \int e^x d x=e^x+C \\
& \int a^x d x=\frac{1}{\log a} a^x+C \quad(a>0, a \neq 1) \\
& \int \frac{1}{x} d x=\log |x|+C
\end{aligned}
